API_name: nchu_course_search_by_type
Description:
{
  "description": "依課程類別（必修／選修）搜尋課程。",
  "required_parameters": [
    {
      "name": "course_type",
      "type": "STRING",
      "description": "Course type to search for (e.g., 必修, 選修)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

